>>> sort_even([5, 3, -5, 2, -3, 3, 9, 0, 123, 1, -10])
[-10, 3, -5, 2, -3, 3, 5, 0, 9, 1, 123]
>>> sort_even([5, 8, -12, 4, 23, 2, 3, 11, 12, -10])
