        }
        もし char が 69 ならば、{
            is_vowel = 1
        }
        もし char が 73 ならば、{
            is_vowel = 1
        }
        もし char が 79 ならば、{
            is_vowel = 1
        }
        もし char が 85 ならば、{
            is_vowel = 1
        }

        もし is_vowel が 1 ならば、{
            countを増やす
        }

        iを増やす
    }

    # Check if last char is 'y' or 'Y'
    もし length が 0 より大きいならば、{
        last_idx = 差(length, 1)
        last_char = s[last_idx]
        もし last_char が 121 ならば、{
            countを増やす
        }
        もし last_char が 89 ならば、{
            countを増やす
        }
    }

    countが答え
