program         = { statement } ;
statement       = ( import_stmt
                  | assert_stmt
                  | assignment
                  | increment
                  | decrement
                  | append
                  | if_stmt
                  | repeat_stmt
                  | funcdef
                  | return_stmt
                  | break_stmt
                  | pass_stmt
                  | expr_stmt ) , LF ;
LF              = /\n/ ;
```

---

## 2. 字句

```
whitespace      = /[ \t\r　]/ ;
line_comment    = ( "#" | "＃" ) , { /[^\n]/ } ;

identifier      = simple_name | extra_name ;
simple_name     = /[A-Za-z_][A-Za-z0-9_]*/ ;
extra_name      = "「" , { /[^」]/ } , "」" ;

integer         = /[0-9]+/ ;
float           = /[0-9]+/ , "." , /[0-9]+/ ;
number          = float | integer ;

string          = '"' , { string_part } , '"' ;
string_part     = string_char | string_escape | string_interp ;
string_char     = /[^"\\{]/ ;
string_escape   = "\\" , /./ ;
string_interp   = "{" , expression , "}" ;
```

---

## 3. 型リテラル

```
literal         = null_lit
                | bool_lit
                | number
                | string
                | array_lit
                | object_lit ;

null_lit        = "値なし" ;
bool_lit        = "真" | "偽" ;

array_lit       = "[" , [ expression , { array_sep , expression } ] , "]" ;
array_sep       = "," | "、" | "，" ;

object_lit      = "{" , [ key_value , { obj_sep , key_value } ] , "}" ;
obj_sep         = "," | "、" | "，" ;
key_value       = string , ":" , expression ;
