                ソート済み[i] = ソート済み[次インデックス]
                ソート済み[次インデックス] = temp
            }
            iを増やす
        }
    }

    # 重複を除去してユニークな配列を作成
    ユニーク = []
    もし 長さ が 0 より大きいならば、{
