                    もし remainder が 1 ならば、{
                        bits1を増やす
                    }
                    temp1 = 商(temp1, 2)
                }
            }

            bits2 = 0
            temp2 = 絶対値(arr[next_j])
            100回、くり返す {
                もし temp2 が 0 より大きいならば、{
                    remainder = 剰余(temp2, 2)
                    もし remainder が 1 ならば、{
                        bits2を増やす
                    }
                    temp2 = 商(temp2, 2)
                }
            }

            # Swap if needed
            should_swap = 0
            もし bits1 が bits2 より大きいならば、{
                should_swap = 1
            }
            もし bits1 が bits2 ならば、{
                もし arr[j] が arr[next_j] より大きいならば、{
                    should_swap = 1
                }
            }

            もし should_swap が 1 ならば、{
                temp = arr[j]
                arr[j] = arr[next_j]
                arr[next_j] = temp
            }
            jを増やす
        }
        iを増やす
    }

    arrが答え
}

